from PyQt6.QtCore import QByteArray, Qt, QTimer
from PyQt6.QtGui import QPixmap
from PyQt6.QtWidgets import QDialog, QLabel, QVBoxLayout

_DURATION_MS = 10000


_OBITO_B64 = b""  # noqa


class ObitoDialog(QDialog):
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setWindowTitle(" ")
        self.setWindowFlags(Qt.WindowType.Dialog | Qt.WindowType.FramelessWindowHint)
        self.setAttribute(Qt.WidgetAttribute.WA_DeleteOnClose)

        layout = QVBoxLayout(self)
        layout.setContentsMargins(10, 10, 10, 10)

        image_label = QLabel()
        image_label.setAlignment(Qt.AlignmentFlag.AlignCenter)
        pixmap = QPixmap()
        pixmap.loadFromData(QByteArray.fromBase64(_OBITO_B64))
        image_label.setPixmap(
            pixmap.scaled(300, 300, Qt.AspectRatioMode.KeepAspectRatio, Qt.TransformationMode.SmoothTransformation)
        )
        layout.addWidget(image_label)

        caption = QLabel("Este es Obito.\nAparecer aquí tenía un 3.14% de probabilidad :).")
        caption.setAlignment(Qt.AlignmentFlag.AlignCenter)
        layout.addWidget(caption)

        QTimer.singleShot(_DURATION_MS, self.close)

    def showEvent(self, a0):
        super().showEvent(a0)
        if (p := self.parent()) is not None:
            center = p.geometry().center()  # ty: ignore
            self.move(center.x() - self.width() // 2, center.y() - self.height() // 2)
